export const INSTANT_EFFECTS: Record<string, (data: SchemaType) => void> = {
  安神香: data => {
    data.云霜凝.心理防线 = Math.max(0, data.云霜凝.心理防线 - 3);
    console.info(`[商店] 安神香：心理防线 -3 → ${data.云霜凝.心理防线}`);
  },
  蚀心露: data => {
    // 显性效果：防线-3, 信任+3, 疑心+3
    data.云霜凝.心理防线 = Math.max(0, data.云霜凝.心理防线 - 3);
    data.云霜凝.信任度 = Math.min(100, data.云霜凝.信任度 + 3);
    data.苗广.疑心值 = Math.min(100, data.苗广.疑心值 + 3);
    console.info(
      `[商店] 蚀心露：防线 -3 → ${data.云霜凝.心理防线}，信任 +3 → ${data.云霜凝.信任度}，疑心 +3 → ${data.苗广.疑心值}`,
    );

    // 隐藏效果：疑心值已进入察觉区间(50-69) + 隔音灵阵 + 未触发过 + 非特殊场景 → 屈辱跳转
    // 2.0.27 修 1: 原代码判 `心态 === '察觉'`,但心态字段由 stateValidation 重算,
    // shopSystem 在前,导致"疑心 49 → +3=52"时心态仍是旧值"疑惑",隐藏效果不触发。
    // 改用疑心值数值范围判定,与 calcMiaoguangMind 的察觉区间(50-69)一致。
    // 2.0.27 修 2: 特殊场景进行中禁用屈辱转换——强转变事件会和场景剧情严重冲突。
    // 显性效果(数值变化)照常,玩家可在场景结束后再次使用触发屈辱转换(前提仍在察觉区间)。
    const 进入察觉区间 = data.苗广.疑心值 >= 50 && data.苗广.疑心值 < 70;
    const 非特殊场景 = !data._特殊场景.进行中;
    if (进入察觉区间 && 非特殊场景 && data.系统.道具状态['隔音灵阵'] === '使用中' && !data._已触发蚀心露屈辱) {
      data._已触发蚀心露屈辱 = true;
      data.苗广.心态 = '屈辱';
      data.苗广.疑心值 = 0; // 重置为0（后半程从0开始计为绿帽值）
      // 写入方式3事件：立即触发AI描写苗广心态转变
      const existing = data._待发送道具事件;
      const event = '__蚀心露屈辱转变__';
      data._待发送道具事件 = existing ? existing + '|||' + event : event;
      console.info('[商店] ⚡ 蚀心露隐藏效果触发！苗广心态→屈辱，疑心值→0');
    }
  },
  定心符: data => {
    data.苗广.疑心值 = Math.max(0, data.苗广.疑心值 - 8);
    console.info(`[商店] 定心符：苗广疑心值 -8 → ${data.苗广.疑心值}`);
  },
  混沌珠: data => {
    // 仅屈辱前有效：疑心值降至当前心态区间下限
    const 心态 = data.苗广.心态;
    if (心态 === '屈辱' || 心态 === '默许' || 心态 === '沉溺' || 心态 === '愤怒') {
      console.warn(`[商店] 混沌珠：${心态}状态无效，不执行`);
      return;
    }
    // 察觉(50~70)→50, 疑惑(25~50)→25, 正常(0~25)→0
    if (心态 === '察觉') data.苗广.疑心值 = 50;
    else if (心态 === '疑惑') data.苗广.疑心值 = 25;
    else data.苗广.疑心值 = 0;
    console.info(`[商店] 混沌珠：疑心值降至区间下限 → ${data.苗广.疑心值}`);
  },
  神魂共鸣石: data => {
    data.云霜凝.信任度 = Math.min(100, data.云霜凝.信任度 + 5);
    console.info(`[商店] 神魂共鸣石：信任度 +5 → ${data.云霜凝.信任度}`);
  },

  // 洛书晴专属消耗品（仅阶段1-2 生效；阶段3+时 script 不再注入提示词）
  安抚符: data => {
    const floor = (globalThis as any).SillyTavern?.chat?.length ?? 0;
    if (data.洛书晴.调教阶段 >= 3) {
      console.warn('[商店] 安抚符在阶段3+不再生效，已静默消耗');
      return;
    }
    data._洛书晴_安抚符生效至 = floor + 3;
    console.info(`[商店] 安抚符：洛书晴敌意软化，生效至楼层${data._洛书晴_安抚符生效至}`);
  },
  真心符: data => {
    const floor = (globalThis as any).SillyTavern?.chat?.length ?? 0;
    if (data.洛书晴.调教阶段 >= 3) {
      console.warn('[商店] 真心符在阶段3+不再生效，已静默消耗');
      return;
    }
    data._洛书晴_真心符生效至 = floor + 3;
    console.info(`[商店] 真心符：洛书晴直接表达内心，生效至楼层${data._洛书晴_真心符生效至}`);
  },
};

