/**
 * 处理装备互斥：激活某装备时，同组其他装备自动卸下
 */
export function enforceExclusiveGroup(itemName: string, data: SchemaType): void {
  for (const [, group] of Object.entries(EXCLUSIVE_GROUPS)) {
    if (!group.includes(itemName)) continue;
    for (const other of group) {
      if (other !== itemName && data.系统.道具状态[other] === '使用中') {
        data.系统.道具状态[other] = '已购买';
        console.info(`[商店] 互斥卸下: ${other}`);
      }
    }
  }
}

/**
 * 装备激活时的副效果（更新服装槽位/妆容字段）
 */
function applyEquipSideEffects(itemName: string, data: SchemaType): void {
  const slot = CLOTHING_SLOT[itemName];
  if (!slot) return;
  if (slot === '特殊配饰') {
    const sub = ACCESSORY_SUB_SLOT[itemName];
    if (sub) {
      data.云霜凝.服装.特殊配饰[sub] = itemName;
      data.云霜凝.服装.暴露程度 = calcExposure(data);
    }
    return;
  }
  data.云霜凝.服装[slot] = itemName;
  data.云霜凝.服装.暴露程度 = calcExposure(data);
}

/**
 * 装备卸下时的副效果（恢复默认服装/妆容）
 */
function applyUnequipSideEffects(itemName: string, data: SchemaType): void {
  const slot = CLOTHING_SLOT[itemName];
  if (!slot) return;
  if (slot === '特殊配饰') {
    const sub = ACCESSORY_SUB_SLOT[itemName];
    if (sub) {
      // 同子槽位是否有其他配饰在使用中（腰部/阴蒂互斥组）
      const otherInSub = Object.entries(ACCESSORY_SUB_SLOT).find(
        ([other, s]) => s === sub && other !== itemName && data.系统.道具状态[other] === '使用中',
      )?.[0];
      data.云霜凝.服装.特殊配饰[sub] = otherInSub ?? '';
      data.云霜凝.服装.暴露程度 = calcExposure(data);
    }
    return;
  }
  const groupName = slot as string;
  const otherInSlot = EXCLUSIVE_GROUPS[groupName]?.find(c => c !== itemName && data.系统.道具状态[c] === '使用中');
  data.云霜凝.服装[slot] = otherInSlot ?? SLOT_DEFAULTS[slot];
  data.云霜凝.服装.暴露程度 = calcExposure(data);
}

/**
 * 检测并处理本轮新激活的道具
 * 在 VARIABLE_UPDATE_ENDED 中调用，比对新旧 道具状态
 */
export function processNewlyActivatedItems(newData: SchemaType, oldData: SchemaType, currentFloor?: number): void {
  const newItems = newData.系统.道具状态;
  const oldItems = oldData.系统.道具状态;
  const floor = currentFloor ?? 0;

  for (const [itemName, newState] of Object.entries(newItems)) {
    const oldState = oldItems[itemName];

    // 存量修复：消耗品卡在"使用中"（新旧都是"使用中"），直接清理并补记冷却
    if (newState === '使用中' && oldState === '使用中' && INSTANT_EFFECTS[itemName]) {
      delete newData.系统.道具状态[itemName];
      const cooldown = CONSUMABLE_COOLDOWN[itemName];
      if (cooldown && floor > 0) {
        newData._消耗品上次使用楼层[itemName] = floor;
      }
      console.warn(`[商店] 存量修复：消耗品 ${itemName} 卡在使用中，已清理并记录冷却`);
      continue;
    }

    // 处理：新="使用中"且旧≠"使用中"（代表刚刚激活，兼容消耗品购买即使用的情况）
    if (newState !== '使用中' || oldState === '使用中') continue;

    console.info(`[商店] 检测到道具激活: ${itemName}`);

    // ─── 神魂空间限制：服装/方式3触发类道具不可激活（消耗品允许） ───
    const inSoulSpace = newData._当前互动模式 === '神魂空间';
    if (inSoulSpace) {
      const isClothing = !!CLOTHING_SLOT[itemName];
      const isScene = isSpecialScene(itemName);

      if (isClothing || isScene) {
        newData.系统.道具状态[itemName] = '已购买';
        console.warn(`[商店] 神魂空间中禁用: ${itemName}，已退回`);
        continue;
      }
    }

    // ─── 消耗品（即时效果） ───────────────────
    if (INSTANT_EFFECTS[itemName]) {
      // 冷却检查：对比当前楼层与上次使用楼层
      const cooldown = CONSUMABLE_COOLDOWN[itemName];
      if (cooldown && floor > 0) {
        const lastUsedFloor = newData._消耗品上次使用楼层[itemName] ?? 0;
        if (lastUsedFloor > 0 && floor - lastUsedFloor < cooldown) {
          // 仍在冷却中，退回为"已购买"
          newData.系统.道具状态[itemName] = '已购买';
          console.warn(
            `[商店] ${itemName} 冷却中（上次楼层${lastUsedFloor}，当前${floor}，需间隔${cooldown}），已退回`,
          );
          continue;
        }
      }

      INSTANT_EFFECTS[itemName](newData);
      delete newData.系统.道具状态[itemName];

      // 记录使用楼层（冷却计时起点）
      if (cooldown && floor > 0) {
        newData._消耗品上次使用楼层[itemName] = floor;
      }
      continue;
    }

    // ─── 永久体改类 ───────────────────────────
    if (BODY_MOD_EFFECTS[itemName]) {
      BODY_MOD_EFFECTS[itemName](newData);
      delete newData.系统.道具状态[itemName];
      console.info(`[商店] ${itemName} 体改已写入`);
      continue;
    }

    // ─── 淫纹刻印（特殊：需要位置+文字参数，格式 "淫纹刻印·<位置>·<文字>"）───
    if (itemName.startsWith('淫纹刻印·')) {
      // 格式: "淫纹刻印·腰腹·母狗" / "淫纹刻印·胸前·{{user}}专用" / "淫纹刻印·大腿内侧·贱货"
      const body = itemName.substring('淫纹刻印·'.length);
      const sep = body.indexOf('·');
      const pos = (sep > 0 ? body.substring(0, sep) : body) as '腰腹' | '胸前' | '大腿内侧' | '臀部';
      const text = sep > 0 ? body.substring(sep + 1) : '';
      if (['腰腹', '胸前', '大腿内侧', '臀部'].includes(pos) && text) {
        // 防止覆盖已有刻印（前端 UI 应阻止，但脚本层也加 guard）
        if (!newData.云霜凝.肉体改造.淫纹[pos]) {
          newData.云霜凝.肉体改造.淫纹[pos] = text;
          console.info(`[商店] 云霜凝淫纹刻印 ${pos}: ${text}`);
        } else {
          console.warn(`[商店] 云霜凝淫纹 ${pos} 已有刻印"${newData.云霜凝.肉体改造.淫纹[pos]}"，跳过写入"${text}"`);
        }
      }
      delete newData.系统.道具状态[itemName];
      continue;
    }

    // ─── 性癖类（槽位装备，最多3个同时使用中） ──
    if (KINK_ITEM_MAP[itemName]) {
      // 统计当前已激活的性癖数量
      const activeKinkCount = Object.keys(newData.系统.道具状态).filter(
        k => KINK_ITEM_MAP[k] && newData.系统.道具状态[k] === '使用中',
      ).length;
      if (activeKinkCount > 3) {
        // 超过3个，退回为已购买
        newData.系统.道具状态[itemName] = '已购买';
        console.warn(`[商店] 性癖槽位已满（${activeKinkCount - 1}/3），${itemName} 已退回`);
      } else {
        console.info(`[商店] ${itemName} 性癖已激活（${activeKinkCount}/3）`);
      }
      continue;
    }

    // ─── 特殊场景触发类（轮次制，类似千晶幻术）───
    if (isSpecialScene(itemName)) {
      newData._特殊场景.进行中 = itemName;
      newData._特殊场景开始楼层 = currentFloor ?? 0;
      delete newData.系统.道具状态[itemName];
      const maxRounds = getSpecialSceneMaxRounds(itemName);
      console.info(`[商店] 特殊场景启动: ${itemName}，共${maxRounds}轮`);
      continue;
    }

    // ─── 留影石（装备toggle：已购买→录制中=使用中） ──
    if (isLiuyingshi(itemName)) {
      // 留影石直接切换为"使用中"（录制中），无互斥
      console.info(`[商店] ${itemName} 留影石开始录制`);
      continue;
    }

    // ─── 装备类（保持"使用中"） ─────────────────
    if (ALL_EQUIPMENT.has(itemName)) {
      enforceExclusiveGroup(itemName, newData);
      applyEquipSideEffects(itemName, newData);
      // 锚神钉全局唯一：装备给云霜凝时，若洛书晴的也是"使用中"则自动卸下
      if (itemName === '锚神钉' && newData._洛书晴道具状态['锚神钉'] === '使用中') {
        newData._洛书晴道具状态['锚神钉'] = '已购买';
        console.info('[商店] 锚神钉全局唯一：从洛书晴自动卸下');
      }
      console.info(`[商店] ${itemName} 装备已激活`);
      continue;
    }

    // ─── 未知道具 ─────────────────────────────
    console.warn(`[商店] 未识别的道具: ${itemName}`);
  }
}

/**
 * 处理洛书晴独立道具状态表中本轮新激活的道具
 * 逻辑对标 processNewlyActivatedItems，但写入洛书晴而非云霜凝
 * 只处理共用道具（服装/体改/性癖/身体器具/部分消耗品）
 */
export function processNewlyActivatedLuoItems(newData: SchemaType, oldData: SchemaType, currentFloor?: number): void {
  const newItems = newData._洛书晴道具状态;
  const oldItems = oldData._洛书晴道具状态;

  for (const [itemName, newState] of Object.entries(newItems)) {
    const oldState = oldItems[itemName];

    if (newState !== '使用中' || oldState === '使用中') continue;

    // 阶段3前服装/体改/性癖不可激活
    if (
      newData.洛书晴.调教阶段 < 3 &&
      (CLOTHING_SLOT[itemName] || BODY_MOD_EFFECTS[itemName] || KINK_ITEM_MAP[itemName])
    ) {
      newData._洛书晴道具状态[itemName] = '已购买';
      console.warn(`[商店] 洛书晴阶段<3，${itemName} 无法激活`);
      continue;
    }

    // ─── 洛书晴消耗品（阶段3+ 时脚本不再注入提示词，但仍执行 INSTANT_EFFECTS）
    if (INSTANT_EFFECTS[itemName]) {
      const cooldown = CONSUMABLE_COOLDOWN[itemName];
      const floor = currentFloor ?? 0;
      if (cooldown && floor > 0) {
        const lastUsedKey = `洛书晴_${itemName}`;
        const lastUsedFloor = newData._消耗品上次使用楼层[lastUsedKey] ?? 0;
        if (lastUsedFloor > 0 && floor - lastUsedFloor < cooldown) {
          newData._洛书晴道具状态[itemName] = '已购买';
          console.warn(`[商店] 洛书晴 ${itemName} 冷却中，已退回`);
          continue;
        }
        newData._消耗品上次使用楼层[lastUsedKey] = floor;
      }
      // 洛书晴消耗品效果（每个道具对洛书晴的作用独立实现，不复用 INSTANT_EFFECTS，
      // 因为后者写入云霜凝数值）
      if (itemName === '安抚符') {
        // 方式2注入：仅设置生效楼层，tone modifier 由 promptInjection 每轮快照追加
        const floor = currentFloor ?? 0;
        if (newData.洛书晴.调教阶段 >= 3) {
          console.warn('[商店] 安抚符在洛书晴阶段3+不再生效，已静默消耗');
        } else {
          newData._洛书晴_安抚符生效至 = floor + 3;
          console.info(`[商店] 安抚符·洛书晴：敌意软化生效至楼层 ${newData._洛书晴_安抚符生效至}`);
        }
      } else if (itemName === '真心符') {
        const floor = currentFloor ?? 0;
        if (newData.洛书晴.调教阶段 >= 3) {
          console.warn('[商店] 真心符在洛书晴阶段3+不再生效，已静默消耗');
        } else {
          newData._洛书晴_真心符生效至 = floor + 3;
          console.info(`[商店] 真心符·洛书晴：直接表达生效至楼层 ${newData._洛书晴_真心符生效至}`);
        }
      } else if (itemName === '安神香') {
        // 即时数值：洛书晴防线-3（设计文档 line 1082）
        const oldDef = newData.洛书晴.心理防线;
        newData.洛书晴.心理防线 = Math.max(0, newData.洛书晴.心理防线 - 3);
        console.info(`[商店] 安神香·洛书晴：心理防线 ${oldDef} → ${newData.洛书晴.心理防线}`);
      } else if (itemName === '神魂共鸣石') {
        // 即时数值：洛书晴顺从+5（设计文档 line 1084）
        const oldObey = newData.洛书晴.顺从度;
        newData.洛书晴.顺从度 = Math.min(100, newData.洛书晴.顺从度 + 5);
        console.info(`[商店] 神魂共鸣石·洛书晴：顺从度 ${oldObey} → ${newData.洛书晴.顺从度}`);
      }
      delete newData._洛书晴道具状态[itemName];
      continue;
    }

    // ─── 洛书晴体改（复用 BODY_MOD_EFFECTS，但写入洛书晴.肉体改造）
    if (BODY_MOD_EFFECTS[itemName]) {
      // 临时重定向：把 data.云霜凝 指向 data.洛书晴 完成体改后恢复
      // 简化：直接在此处手写共用逻辑（避免 BODY_MOD_EFFECTS 硬绑云霜凝）
      applyBodyModToLuo(itemName, newData);
      delete newData._洛书晴道具状态[itemName];
      console.info(`[商店] 洛书晴 ${itemName} 体改已写入`);
      continue;
    }

    // ─── 淫纹刻印（格式："淫纹刻印·<位置>·<文字>"）
    if (itemName.startsWith('淫纹刻印·')) {
      const body = itemName.substring('淫纹刻印·'.length);
      const sep = body.indexOf('·');
      const pos = (sep > 0 ? body.substring(0, sep) : body) as '腰腹' | '胸前' | '大腿内侧' | '臀部';
      const text = sep > 0 ? body.substring(sep + 1) : '';
      if (['腰腹', '胸前', '大腿内侧', '臀部'].includes(pos) && text) {
        // 防止覆盖已有刻印
        if (!newData.洛书晴.肉体改造.淫纹[pos]) {
          newData.洛书晴.肉体改造.淫纹[pos] = text;
          console.info(`[商店] 洛书晴淫纹刻印 ${pos}: ${text}`);
        } else {
          console.warn(`[商店] 洛书晴淫纹 ${pos} 已有刻印"${newData.洛书晴.肉体改造.淫纹[pos]}"，跳过写入"${text}"`);
        }
      }
      delete newData._洛书晴道具状态[itemName];
      continue;
    }

    // ─── 性癖道具（最多3个使用中，洛书晴独立槽位）
    if (KINK_ITEM_MAP[itemName]) {
      const activeKinkCount = Object.keys(newData._洛书晴道具状态).filter(
        k => KINK_ITEM_MAP[k] && newData._洛书晴道具状态[k] === '使用中',
      ).length;
      if (activeKinkCount > 3) {
        newData._洛书晴道具状态[itemName] = '已购买';
        console.warn(`[商店] 洛书晴性癖槽位已满`);
      } else {
        // 2.0.22 修复: 兜底同步到 data.洛书晴.性癖列表(ShopPanel 已在前端立即写,
        // 此处保护 AI JSONPatch 或其他路径装载的情况)
        const kinkDef = KINK_ITEM_MAP[itemName];
        if (kinkDef && !newData.洛书晴.性癖列表[kinkDef.name]) {
          newData.洛书晴.性癖列表[kinkDef.name] = kinkDef.tag;
        }
      }
      continue;
    }

    // ─── 服装：写入 洛书晴.服装（无暴露等级计算）
    const slot = CLOTHING_SLOT[itemName];
    if (slot) {
      if (slot === '特殊配饰') {
        const sub = ACCESSORY_SUB_SLOT[itemName];
        if (sub) newData.洛书晴.服装.特殊配饰[sub] = itemName;
      } else {
        newData.洛书晴.服装[slot] = itemName;
      }
      continue;
    }

    // ─── 身体器具（保持"使用中"即可，注入时从状态表读取）
    if (ALL_EQUIPMENT.has(itemName)) {
      // 锚神钉全局唯一：装备给洛书晴时，云霜凝的自动卸下
      if (itemName === '锚神钉' && newData.系统.道具状态['锚神钉'] === '使用中') {
        newData.系统.道具状态['锚神钉'] = '已购买';
        console.info('[商店] 锚神钉全局唯一：从云霜凝自动卸下');
      }
      continue;
    }
  }
}

