      data.洛书晴.顺从度 = Math.min(100, data.洛书晴.顺从度 + 3);
      data.苗喧.绝望值 = Math.min(100, data.苗喧.绝望值 + 3);
      data.苗喧.压抑值 = Math.min(100, data.苗喧.压抑值 + 8);
