const LIUYINGSHI_PRICE = 60;
const LIUYINGSHI_SELL_COOLDOWN = 15; // 出售冷却：15楼

/**
 * 购买一块新留影石
 * 返回 { success, reason, itemName }
 */
export function buyLiuyingshi(data: SchemaType): { success: boolean; reason: string; itemName: string } {
  if (data.系统.灵石 < LIUYINGSHI_PRICE) {
    return { success: false, reason: `灵石不足（需${LIUYINGSHI_PRICE}）`, itemName: '' };
  }
  // 解锁条件：阶段≥3
  if (data.治疗.阶段 < 3) {
    return { success: false, reason: '阶段≥3解锁', itemName: '' };
  }

  data.系统.灵石 -= LIUYINGSHI_PRICE;
  data._留影石计数 += 1;
  const itemName = `留影石_${data._留影石计数}`;
  data.系统.道具状态[itemName] = '已购买';
  console.info(`[商店] 购买留影石: ${itemName}，剩余灵石: ${data.系统.灵石}`);
  return { success: true, reason: '', itemName };
}

/**
 * 出售一块已录制的留影石给苗广
 * 出售后留影石回到"已购买"状态（可重复使用），全局进入冷却
 * 返回 { success, reason }
 */
export function sellLiuyingshi(
  data: SchemaType,
  itemName: string,
  currentFloor: number,
): { success: boolean; reason: string } {
  if (!isLiuyingshi(itemName)) {
    return { success: false, reason: '不是留影石' };
  }
  const state = data.系统.道具状态[itemName];
  if (state !== '使用中') {
    return { success: false, reason: '留影石未在录制中' };
  }

  const 心态 = data.苗广.心态;
  // 仅默许/沉溺可出售
  if (心态 !== '默许' && 心态 !== '沉溺') {
    return { success: false, reason: '苗广心态未达默许' };
  }
  // 需先完成夫前凌辱（苗广至少亲眼目击过一次）
  if (!data._已完成特殊场景['夫前凌辱']) {
    return { success: false, reason: '需先完成「夫前凌辱」' };
  }

  // 全局冷却检查
  if (currentFloor > 0) {
    const lastSoldFloor = data._留影石上次出售楼层 ?? 0;
    if (lastSoldFloor > 0 && currentFloor - lastSoldFloor < LIUYINGSHI_SELL_COOLDOWN) {
      const remaining = LIUYINGSHI_SELL_COOLDOWN - (currentFloor - lastSoldFloor);
      return { success: false, reason: `出售冷却中（还需${remaining}楼）` };
    }
  }

  const price = 心态 === '沉溺' ? 800 : 500;
  data.系统.灵石 += price;
  // 回到已购买状态（可重复录制出售）
  data.系统.道具状态[itemName] = '已购买';
  // 记录出售楼层（全局冷却）
  if (currentFloor > 0) {
    data._留影石上次出售楼层 = currentFloor;
  }

  // 方式3事件
  const eventKey = 心态 === '沉溺' ? '__留影石出售_沉溺__' : '__留影石出售_默许__';
  const existing = data._待发送道具事件;
  data._待发送道具事件 = existing ? existing + '|||' + eventKey : eventKey;
  data._系统操作中 = true;

  console.info(`[商店] 留影石出售: ${itemName}，售价${price}灵石，心态=${心态}，冷却${LIUYINGSHI_SELL_COOLDOWN}楼`);
  return { success: true, reason: '' };
}

/**
 * 查询留影石出售是否仍在冷却中
 */
export function getLiuyingshiSellCooldownInfo(
  data: SchemaType,
  currentFloor: number,
): { inCooldown: boolean; remainingFloors: number } {
  if (currentFloor <= 0) return { inCooldown: false, remainingFloors: 0 };
  const lastSoldFloor = data._留影石上次出售楼层 ?? 0;
  if (lastSoldFloor <= 0) return { inCooldown: false, remainingFloors: 0 };
  const elapsed = currentFloor - lastSoldFloor;
  if (elapsed >= LIUYINGSHI_SELL_COOLDOWN) return { inCooldown: false, remainingFloors: 0 };
  return { inCooldown: true, remainingFloors: LIUYINGSHI_SELL_COOLDOWN - elapsed };
}

// ────────────────────────────────────────────
// 消耗品冷却查询（供前端使用）
// ────────────────────────────────────────────

/**
 * 查询消耗品是否仍在冷却中
 * @returns { inCooldown, remainingFloors } — inCooldown=true 时不可使用
 */
export function getConsumableCooldownInfo(
  itemName: string,
  data: SchemaType,
  currentFloor: number,
): { inCooldown: boolean; remainingFloors: number } {
  const cooldown = CONSUMABLE_COOLDOWN[itemName];
  if (!cooldown || currentFloor <= 0) return { inCooldown: false, remainingFloors: 0 };

  const lastUsedFloor = data._消耗品上次使用楼层[itemName] ?? 0;
  if (lastUsedFloor <= 0) return { inCooldown: false, remainingFloors: 0 };

  const elapsed = currentFloor - lastUsedFloor;
  if (elapsed >= cooldown) return { inCooldown: false, remainingFloors: 0 };

  return { inCooldown: true, remainingFloors: cooldown - elapsed };
}

/**
 * 查询道具在当前状态下是否可激活
 * 综合判断：冷却 + 神魂空间限制
 */
export function canActivateItem(
  itemName: string,
  data: SchemaType,
  currentFloor: number,
): { allowed: boolean; reason: string } {
  // 神魂空间限制：服装 + 方式3触发类（消耗品允许）
  if (data._当前互动模式 === '神魂空间') {
    if (CLOTHING_SLOT[itemName]) return { allowed: false, reason: '神魂空间中无法更换服装' };
    if (isSpecialScene(itemName)) return { allowed: false, reason: '神魂空间中无法触发特殊场景' };
  }

  // 消耗品冷却
  const { inCooldown, remainingFloors } = getConsumableCooldownInfo(itemName, data, currentFloor);
  if (inCooldown) return { allowed: false, reason: `冷却中（还需${remainingFloors}楼）` };

  return { allowed: true, reason: '' };
}

/**
 * 从道具状态重建服装字段（修复 MVU 传播延迟导致快照不一致的问题）
 *
 * 场景：前端 equipClothing → store.flush() → /send 创建新消息，
 * 但 MVU 数据可能未传播到新消息，导致 PROMPT_READY 快照捕获旧服装值。
 * validateAndRecalcState 硬回滚到快照后，processNewlyActivatedItems
 * 因新旧道具状态都是"使用中"而检测不到变化，服装字段不会被修复。
 *
 * 此函数遍历道具状态，以"使用中"的服装道具为准重建服装槽位。
 * 在 VARIABLE_UPDATE_ENDED 的全部处理完成后调用。
 */
export function syncClothingFromState(data: SchemaType): void {
  let changed = false;
  for (const [itemName, state] of Object.entries(data.系统.道具状态)) {
    if (state !== '使用中') continue;
    const slot = CLOTHING_SLOT[itemName];
    if (!slot) continue;
    if (slot === '特殊配饰') {
      const sub = ACCESSORY_SUB_SLOT[itemName];
      if (sub && data.云霜凝.服装.特殊配饰[sub] !== itemName) {
        data.云霜凝.服装.特殊配饰[sub] = itemName;
        changed = true;
        console.info(`[商店] 服装同步修复: 特殊配饰.${sub} → ${itemName}`);
      }
      continue;
    }
    if (data.云霜凝.服装[slot] !== itemName) {
      data.云霜凝.服装[slot] = itemName;
      changed = true;
      console.info(`[商店] 服装同步修复: ${slot} → ${itemName}`);
    }
  }
  if (changed) {
    data.云霜凝.服装.暴露程度 = calcExposure(data);
  }
}
